----------------------- cooper nai 'ΔΥΤΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ','ΚΕΝΤΡΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ','ΑΝΑΤΟΛΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ ΚΑΙ ΘΡΑΚΗΣ'
update DYGXTRADER2 
set DYGXTRADER2.DYYN = 1 
where DYGXTRADER2.DYGXTRADER2_FIELD4 = '2cb83d1f-53b6-4834-b9fa-2ea999a343bb' 
and DYGXTRADER2.GXTRADERID in 
(select GXTRADER.GXID from GxCUSTOMER
inner join GXTRADER on GXTRADER.GXID = GxCUSTOMER.GXTRDRID
inner join Z_CUSTOMER_CATEGORY_ZONESPOL on Z_CUSTOMER_CATEGORY_ZONESPOL.CUSTCODE = GxCUSTOMER.GXCODE
where Z_CUSTOMER_CATEGORY_ZONESPOL.GXDESCRIPTION in ('ΔΥΤΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ','ΚΕΝΤΡΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ','ΑΝΑΤΟΛΙΚΗΣ ΜΑΚΕΔΟΝΙΑΣ ΚΑΙ ΘΡΑΚΗΣ') and GXTRADER.GXBOOLEANFIELD1 = 1 )
and DYGXTRADER2.GXTRADERID = @trdrid
---------------- double coin oxi ΠΕΛΟΠΟΝΝΗΣΟΣ

update DYGXTRADER2 
set DYGXTRADER2.DYYN =  0
where DYGXTRADER2.DYGXTRADER2_FIELD4 = '3D13EF9E-CBC8-485A-B478-CDD7027FEC4E' 
and DYGXTRADER2.GXTRADERID in 
(select GXTRADER.GXID from GxCUSTOMER
inner join GXTRADER on GXTRADER.GXID = GxCUSTOMER.GXTRDRID
inner join Z_CUSTOMER_CATEGORY_ZONESPOL on Z_CUSTOMER_CATEGORY_ZONESPOL.CUSTCODE = GxCUSTOMER.GXCODE
where Z_CUSTOMER_CATEGORY_ZONESPOL.GXDESCRIPTION in ('ΠΕΛΟΠΟΝΝΗΣΟΥ') and GXTRADER.GXBOOLEANFIELD1 = 1 )
and DYGXTRADER2.GXTRADERID = @trdrid


--ΕΞΑΙΡΕΣΗ SAILUN ΟΛΑ ΓΙΑ ΤΗΝ ΚΑΤΗΓΟΡΙΑ ΝΟΜΟΥ ΚΑΙ ΣΥΓΚΕΚΡΙΜΕΝΕΣ ΚΑΤΗΓΟΡΙΕΣ
update DYGXTRADER2 
set DYGXTRADER2.DYYN =  0
where DYGXTRADER2.DYGXTRADER2_FIELD4 = '98643C3D-BE40-E6A6-AB67-01891A9792F0'
and DYGXTRADER2.GXTRADERID in 
(select GXTRADER.GXID from GxCUSTOMER
inner join GXTRADER on GXTRADER.GXID = GxCUSTOMER.GXTRDRID
inner join Z_CUSTOMER_CATEGORY_NOMOS on Z_CUSTOMER_CATEGORY_NOMOS.CUSTCODE = GxCUSTOMER.GXCODE
where
Z_CUSTOMER_CATEGORY_NOMOS.GXDESCRIPTION in ('ΙΩΑΝΝΙΝΩΝ', 'ΑΡΤΑΣ','ΠΡΕΒΕΖΑΣ','ΘΕΣΠΡΩΤΙΑΣ','ΗΡΑΚΛΕΙΟΥ','ΧΑΝΙΩΝ','ΡΕΘΥΜΝΗΣ','ΛΑΣΙΘΙΟΥ') 
and GXTRADER.GXBOOLEANFIELD1 = 1 )
and DYGXTRADER2.GXTRADERID = @trdrid


--ΕΞΑΙΡΕΣΗ SAILUN ΟΛΑ ΓΙΑ ΤΟΥΣ ΠΕΛΑΤΕΣ ΜΕ ΔΗΜΟ/ΠΟΛΗ = ΠΑΡΟΣ ΣΥΡΟΣ ΝΑΞΟΣ 
update DYGXTRADER2 
set DYGXTRADER2.DYYN =  0
where DYGXTRADER2.DYGXTRADER2_FIELD4 = '98643C3D-BE40-E6A6-AB67-01891A9792F0'
and DYGXTRADER2.GXTRADERID in 
(select GXTRADER.GXID from GxCUSTOMER
inner join GXTRADER on GXTRADER.GXID = GxCUSTOMER.GXTRDRID
inner join gxTraderSite ON gxTraderSite.GXTRDRID = GXTRADER.GXID AND gxAddressStatus = 2
INNER JOIN gxRegion ON gxRegion.GXID = GXTRADERSITE.GXREGNID
where
GXREGION.GXDESCRIPTION in ('ΣΥΡΟΣ','ΠΑΡΟΣ','ΝΑΞΟΣ') 
and GXTRADER.GXBOOLEANFIELD1 = 1 )
and DYGXTRADER2.GXTRADERID = @trdrid


----ΕΞΑΙΡΕΣΗ SAILUN ΦΟΡΤΗΓΟ ΓΙΑ ΤΟΥΣ ΠΕΛΑΤΕΣ ΜΕ ΔΗΜΟ/ΠΟΛΗ = ΑΣΠΟΠΥΡΓΟΣ
update DYGXTRADER2 
set DYGXTRADER2.DYYN =  0
where DYGXTRADER2.DYGXTRADER2_FIELD4 = '98643C3D-BE40-E6A6-AB67-01891A9792F0' 
AND DYGXTRADER2.DYGXTRADER2_FIELD5 = '2a1c9bef-6011-4c03-a954-5238e6b62aa2'
and DYGXTRADER2.GXTRADERID in 
(select GXTRADER.GXID from GxCUSTOMER
inner join GXTRADER on GXTRADER.GXID = GxCUSTOMER.GXTRDRID
inner join gxTraderSite ON gxTraderSite.GXTRDRID = GXTRADER.GXID AND gxAddressStatus = 2
INNER JOIN gxRegion ON gxRegion.GXID = GXTRADERSITE.GXREGNID
where
GXREGION.GXDESCRIPTION in ('ΑΣΠΡΟΠΥΡΓΟΣ') 
and GXTRADER.GXBOOLEANFIELD1 = 1)and DYGXTRADER2.GXTRADERID = @trdrid


---------------------- ΦΙΛΤΡΑ ΕΓΓΥΗΣΕΙΣ
end;


